"""
MABE Bootstrap: Full Extended Optical Physics

Run: python3 bootstrap_optical_full.py

Prereqs: optical/ M1-M9 (from 0001_optical_module.patch)
         pip install miepython scipy

Creates 8 files:
  optical/multiple_scattering.py    — M6b: thickness-dependent MS correction
  optical/base_layer.py             — Primer/functionalization layer model
  optical/janus_sphere.py           — Janus two-way color
  optical/inverse_design.py         — M11: scipy inverse design
  optical/click_linker.py           — M10: material-specific click attachment
  tests/test_optical/test_extended_optics.py  — 19 tests
  tests/test_optical/test_inverse_design.py   — 14 tests
  tests/test_optical/test_click_linker.py     — 30 tests

Click linker covers: SiO2, TiO2, Fe2O3, carbon, Au, polystyrene
  Anchors: APTES, MPTMS, catechol, phosphonate, thiol, diazonium, pyrene
  Spacers: PEG2/4/8/12, alkyl C6/C11, none
  Click: SPAAC, CuAAC, thiol-maleimide, IEDDA

Total optical: 89 tests, 0 failed
"""
import base64, pathlib

FILES = {
    "optical/multiple_scattering.py": "",
    "optical/base_layer.py": "",
    "optical/janus_sphere.py": "",
    "optical/inverse_design.py": "",
    "optical/click_linker.py": "",
    "tests/test_optical/test_extended_optics.py": "",
    "tests/test_optical/test_inverse_design.py": "",
    "tests/test_optical/test_click_linker.py": "",
}

def main():
    for path, b64 in FILES.items():
        p = pathlib.Path(path)
        p.parent.mkdir(parents=True, exist_ok=True)
        p.write_bytes(base64.b64decode(b64))
        print(f"  Wrote {path} ({len(base64.b64decode(b64)):,} bytes)")
    print()
    print("  python3 -m pytest tests/test_optical/ -v")

if __name__ == "__main__":
    main()